GUICommonActivityTab = class("GUICommonActivityTab", IGUIWindow) ---@class GUICommonActivityTab

function GUICommonActivityTab:onLoad()
    self.ivSelected = self:getChildWindowByName("CommonActivityTab-Selected", GUIType.StaticImage)
    self.ivSelected:SetVisible(false)
    self.ivText = self:getChildWindowByName("CommonActivityTab-Text", GUIType.StaticText)
    self.btnClick = self:getChildWindowByName("CommonActivityTab-Click", GUIType.Button)
    self.btnClick:registerEvent(GUIEvent.ButtonClick, function()
        GUICommonActivityLayout:showActivity(self.activityId)
    end)
end

function GUICommonActivityTab:onDataChanged(activity)
    self.activityId = activity.id
    self.ivText:SetText(Lang:getString(activity.tabLang))
end

function GUICommonActivityTab:setSelected(selected)
    self.ivSelected:SetVisible(selected)
    self.btnClick:SetTouchable(not selected)
end

function GUICommonActivityTab:isSelected()
    return self.ivSelected:IsVisible()
end

return GUICommonActivityTab